<template><PageHeader title="OTA 包管理"><el-button type="primary" @click="add">发布测试包</el-button></PageHeader><div class="grid"><MetricCard label="总数" :value="summary.total"/><MetricCard label="已发布" :value="summary.published"/><MetricCard label="强制升级" :value="summary.mandatory"/><MetricCard label="平均灰度" :value="summary.averageRollout+'%'"/></div><div class="panel"><el-table :data="rows"><el-table-column prop="type" label="类型"/><el-table-column prop="version" label="版本"/><el-table-column prop="rolloutPercent" label="灰度%"/><el-table-column prop="status" label="状态"/></el-table></div></template><script setup lang="ts">import{computed,onMounted,ref}from'vue';import PageHeader from'@/components/PageHeader.vue';import MetricCard from'@/components/MetricCard.vue';import{adminApi}from'@/services/admin-api';import{otaSummary}from'@/view-models';const rows=ref<any[]>([]),summary=computed(()=>otaSummary(rows.value));async function load(){rows.value=await adminApi.ota()}async function add(){await adminApi.addOta({type:'kids_content',version:`2.0.${Date.now()}`,url:'https://cdn.example.com/kids.zip',sha256:'a'.repeat(64),mandatory:false,compatibleModels:['QXR-S3'],rolloutPercent:10});await load()}onMounted(load);</script>
